} else {
  $new_node_path="/proc/cygdrive/d/User/Desktop/项目/my_minttr(2)/worker/node_modules/.pnpm/wrangler@4.83.0_@cloudflare+workers-types@4.20260418.1/node_modules/wrangler/bin/node_modules:/proc/cygdrive/d/User/Desktop/项目/my_minttr(2)/worker/node_modules/.pnpm/wrangler@4.83.0_@cloudflare+workers-types@4.20260418.1/node_modules/wrangler/node_modules:/proc/cygdrive/d/User/Desktop/项目/my_minttr(2)/worker/node_modules/.pnpm/wrangler@4.83.0_@cloudflare+workers-types@4.20260418.1/node_modules:/proc/cygdrive/d/User/Desktop/项目/my_minttr(2)/worker/node_modules/.pnpm/node_modules"
